using UnityEngine;

public static class RhythmGenerator
{
    private static List<float[]> measurePatterns = new List<float[]>
    {
        new float[] { 0f, 1f, 2f, 3f },
        new float[] { 0f, 2f, 3f },
        new float[] { 0f, 1f, 2.5f },
        new float[] { 0f, 1.5f, 2f, 3.5f },
        new float[] { 0f, 0.5f, 1.5f, 2.5f },
        new float[] { 0f, 2f },
        new float[] { 0f, 1f, 3f }
    };

    public static MusicLineData GenerateRandomLine()
    {
        MusicLineData line = new MusicLineData();

        for (int measure = 0; measure < line.measureCount; measure++)
        {
            float measureStartBeat = measure * line.beatsPerMeasure;

            float[] chosenPattern = measurePatterns[Random.Range(0, measurePatterns.Count)];

            foreach (float beatInMeasure in chosenPattern)
            {
                NoteEvent note = new NoteEvent();
                note.beatPosition = measureStartBeat + beatInMeasure;
                line.notes.Add(note);
            }
        }

        line.notes.Sort((a, b) => a.beatPosition.CompareTo(b.beatPosition));

        return line;
    }
}

using UnityEngine;

public class LineSegment : MonoBehaviour
{
    public Transform notesParent;
    public Transform barLinesParent;
    public GameObject notePrefab;

    public float lineWidth = 16f;
    public float noteY = 0.8f;
    public float barLineHeight = 1.5f;

    private MusicLineData currentData;

    public void BuildLine(MusicLineData lineData)
    {
        currentData = lineData;

        ClearChildren(notesParent);
        ClearChildren(barLinesParent);

        CreateBarLines();
        CreateNotes();
    }

    void CreateNotes()
    {
        if (currentData == null) return;

        float totalBeats = currentData.TotalBeats;
        float leftX = -lineWidth / 2f;
        float rightX = lineWidth / 2f;

        foreach (NoteEvent note in currentData.notes)
        {
            float t = note.beatPosition / totalBeats;
            float x = Mathf.Lerp(leftX, rightX, t);

            GameObject noteObj = Instantiate(notePrefab, notesParent);
            noteObj.transform.localPosition = new Vector3(x, noteY, 0f);
        }
    }

    void CreateBarLines()
    {
        if (currentData == null) return;

        float totalBeats = currentData.TotalBeats;
        float leftX = -lineWidth / 2f;
        float rightX = lineWidth / 2f;

        for (int measure = 1; measure < currentData.measureCount; measure++)
        {
            float beatPosition = measure * currentData.beatsPerMeasure;
            float t = beatPosition / totalBeats;
            float x = Mathf.Lerp(leftX, rightX, t);

            GameObject barLine = new GameObject("BarLine");
            barLine.transform.SetParent(barLinesParent);
            barLine.transform.localPosition = new Vector3(x, 0.5f, 0f);

            SpriteRenderer sr = barLine.AddComponent<SpriteRenderer>();
            sr.sprite = notePrefab.GetComponent<SpriteRenderer>().sprite;
            sr.color = Color.black;

            barLine.transform.localScale = new Vector3(0.05f, barLineHeight, 1f);
        }
    }

    void ClearChildren(Transform parent)
    {
        for (int i = parent.childCount - 1; i >= 0; i--)
        {
            Destroy(parent.GetChild(i).gameObject);
        }
    }
}

using UnityEngine;

public class LineManager : MonoBehaviour
{
    public LineSegment linePrefab;

    public Vector3 currentLinePosition = new Vector3(0f, 0f, 0f);
    public Vector3 previewLinePosition = new Vector3(0f, -2.5f, 0f);

    private LineSegment currentLine;
    private LineSegment previewLine;

    void Start()
    {
        SpawnInitialLines();
    }

    void SpawnInitialLines()
    {
        MusicLineData currentData = RhythmGenerator.GenerateRandomLine();
        MusicLineData previewData = RhythmGenerator.GenerateRandomLine();

        currentLine = Instantiate(linePrefab, currentLinePosition, Quaternion.identity);
        currentLine.BuildLine(currentData);

        previewLine = Instantiate(linePrefab, previewLinePosition, Quaternion.identity);
        previewLine.BuildLine(previewData);

        SetPreviewLook(previewLine);
    }

    public void AdvanceLine()
    {
        if (currentLine != null)
        {
            Destroy(currentLine.gameObject);
        }

        currentLine = previewLine;
        currentLine.transform.position = currentLinePosition;
        SetCurrentLook(currentLine);

        MusicLineData newPreviewData = RhythmGenerator.GenerateRandomLine();
        previewLine = Instantiate(linePrefab, previewLinePosition, Quaternion.identity);
        previewLine.BuildLine(newPreviewData);
        SetPreviewLook(previewLine);
    }

    void SetPreviewLook(LineSegment line)
    {
        SpriteRenderer[] renderers = line.GetComponentsInChildren<SpriteRenderer>();

        foreach (SpriteRenderer sr in renderers)
        {
            Color c = sr.color;
            c.a = 0.4f;
            sr.color = c;
        }
    }

    void SetCurrentLook(LineSegment line)
    {
        SpriteRenderer[] renderers = line.GetComponentsInChildren<SpriteRenderer>();

        foreach (SpriteRenderer sr in renderers)
        {
            Color c = sr.color;
            c.a = 1f;
            sr.color = c;
        }
    }
}

